ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?attendance a :Attendance .
    ?student a :Students .
    ?attendance p:hasStudent ?student .
    ?attendance p:Date ?date .
    ?attendance p:Status ?status_f .
    FILTER(STR(?status_f) = "Present")
    BIND(?date AS ?o0)
  }
  UNION
  {
    ?grades a :Grades .
    ?student a :Students .
    ?grades p:hasStudent ?student .
    ?grades p:Score ?score .
    ?student p:name ?name_f .
    FILTER(STR(?name_f) = "Alice Johnson")
    BIND(?score AS ?o0)
  }
} }
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?attendance a :Attendance .
    ?student a :Students .
    ?attendance p:hasStudent ?student .
    ?attendance p:Date ?date .
    ?student p:name ?name_f .
    ?attendance p:Status ?status_f .
    FILTER(STR(?name_f) = "Alice Johnson")
    FILTER(STR(?status_f) = "Present")
    BIND(?date AS ?o0)
  }
  UNION
  {
    ?grades a :Grades .
    ?student a :Students .
    ?grades p:hasStudent ?student .
    ?grades p:Score ?score .
    ?student p:name ?name_f .
    FILTER(STR(?name_f) = "Alice Johnson")
    BIND(?score AS ?o0)
  }
} }
}
